import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Button,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  ListItemButton,
  Menu,
  MenuItem,
  Divider,
  useTheme,
  InputAdornment,
  IconButton,
  Dialog,
  DialogContent,
  DialogActions,
  DialogTitle,
  CircularProgress,
  Snackbar,
  Alert,
  TextField,
  Paper,
  Autocomplete,
  Link,
  Popper,
  ClickAwayListener,
  MenuList,
  Chip,
} from '@mui/material';
import {
  AccountCircle,
  HowToReg,
  QrCodeScanner,
  Phone,
  Send,
  History,
  VisibilityOff,
  Visibility,
  Email,
  Security,
  Google,
  Facebook,
  Apple,
  Login,
  LockReset,
  Close,
  Search,
  FilterList,
  Timeline,
  Business,
  Verified,
  Person,
  Message,
  Clear,
  TrendingUp,
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';

const features = [
  {
    icon: <Timeline sx={{ fontSize: 40 }} />,
    title: 'Truy xuất nguồn gốc',
    description: 'Theo dõi toàn bộ quá trình từ sản xuất đến tiêu thụ sản phẩm',
    color: 'primary',
    image: 'https://images.unsplash.com/photo-1586773860418-d37222d8fce3?ixlib=rb-1.2.1&auto=format&fit=crop&w=1350&q=80',
  },
  {
    icon: <Business sx={{ fontSize: 40 }} />,
    title: 'Quản lý doanh nghiệp',
    description: 'Công cụ quản lý sản phẩm và chuỗi cung ứng cho doanh nghiệp',
    color: 'secondary',
    image: 'https://images.unsplash.com/photo-1552664730-d307ca884978?ixlib=rb-1.2.1&auto=format&fit=crop&w=1350&q=80',
  },
  {
    icon: <Verified sx={{ fontSize: 40 }} />,
    title: 'Chứng nhận chất lượng',
    description: 'Xác thực và chứng nhận chất lượng sản phẩm',
    color: 'success',
    image: 'https://images.unsplash.com/photo-1579113800032-c38bd7635818?ixlib=rb-1.2.1&auto=format&fit=crop&w=1350&q=80',
  },
